package cache

import (
	"encoding/json"
	"os"
	"path/filepath"
	"testing"
	"time"
)

func TestSetUsesPrivatePermissions(t *testing.T) {
	s := New(filepath.Join(t.TempDir(), "cache"), time.Hour)

	s.Set("dags", json.RawMessage(`{"ok":true}`))

	assertPrivateCachePermissions(t, s, "dags")
}

func TestSetTightensExistingPublicPermissions(t *testing.T) {
	s := New(filepath.Join(t.TempDir(), "cache"), time.Hour)
	path := s.path("dags")

	if err := os.MkdirAll(s.Dir, 0o755); err != nil {
		t.Fatalf("create public cache dir: %v", err)
	}
	if err := os.WriteFile(path, []byte(`{"old":true}`), 0o644); err != nil {
		t.Fatalf("create public cache file: %v", err)
	}

	s.Set("dags", json.RawMessage(`{"ok":true}`))

	assertPrivateCachePermissions(t, s, "dags")
}

func assertPrivateCachePermissions(t *testing.T, s *Store, key string) {
	t.Helper()

	dirInfo, err := os.Stat(s.Dir)
	if err != nil {
		t.Fatalf("stat cache dir: %v", err)
	}
	if got := dirInfo.Mode().Perm(); got != 0o700 {
		t.Fatalf("cache dir mode = %o, want 700", got)
	}

	fileInfo, err := os.Stat(s.path(key))
	if err != nil {
		t.Fatalf("stat cache file: %v", err)
	}
	if got := fileInfo.Mode().Perm(); got != 0o600 {
		t.Fatalf("cache file mode = %o, want 600", got)
	}
}
